    int rank = MPI_Comm_rank(MPI_COMM_WORLD);

    if (rank == 0) { // Rank 0 is responsible for collecting results from other ranks
        double minDist = std::numeric_limits<double>::max();
        for (int i = 1; i < numRanks; ++i) {
